# Dynamic Query to Filter User Data in MongoDB

## Method 1: Basic Find Query (Simple)

```javascript
const mongoose = require('mongoose');

// Basic filter
const maleUsers = await db.collection('user_data').find({ gender: 'Male' }).toArray();
console.log(maleUsers);
```

## Method 2: Dynamic Query Builder (Recommended)

```javascript
async function filterUserData(filterCriteria) {
  const query = {};

  // Build dynamic query
  if (filterCriteria.gender) {
    query.gender = filterCriteria.gender;
  }
  if (filterCriteria.username) {
    query.username = { $regex: filterCriteria.username, $options: 'i' }; // Case-insensitive
  }

  const results = await db.collection('user_data').find(query).toArray();
  return results;
}

// Usage
const maleUsers = await filterUserData({ gender: 'Male' });
```

## Method 3: Mongoose Schema Approach

```javascript
const userSchema = new mongoose.Schema({
  username: String,
  gender: String
});

const User = mongoose.model('user_data', userSchema);

// Simple filter
const maleUsers = await User.find({ gender: 'Male' });

// Or with more options
const maleUsers = await User.find({ gender: 'Male' })
  .select('username gender')
  .limit(100)
  .sort({ username: 1 });
```

## Method 4: Advanced Dynamic Query with Pagination & Sorting

```javascript
async function dynamicUserFilter(filters, options = {}) {
  const {
    page = 1,
    limit = 10,
    sortBy = '_id',
    sortOrder = 1
  } = options;

  const query = {};

  // Dynamic filters
  Object.keys(filters).forEach(key => {
    if (filters[key]) {
      if (key === 'username') {
        query[key] = { $regex: filters[key], $options: 'i' };
      } else {
        query[key] = filters[key];
      }
    }
  });

  const skip = (page - 1) * limit;

  const results = await db.collection('user_data')
    .find(query)
    .sort({ [sortBy]: sortOrder })
    .skip(skip)
    .limit(limit)
    .toArray();

  const total = await db.collection('user_data').countDocuments(query);

  return {
    data: results,
    total,
    page,
    pages: Math.ceil(total / limit)
  };
}

// Usage
const result = await dynamicUserFilter(
  { gender: 'Male' },
  { page: 1, limit: 20, sortBy: 'username' }
);
```

## Method 5: Express.js Endpoint with Query Parameters

```javascript
app.get('/users', async (req, res) => {
  try {
    const { gender, username, page = 1, limit = 10 } = req.query;

    const query = {};
    if (gender) query.gender = gender;
    if (username) query.username = { $regex: username, $options: 'i' };

    const skip = (page - 1) * limit;

    const users = await db.collection('user_data')
      .find(query)
      .skip(skip)
      .limit(parseInt(limit))
      .toArray();

    const total = await db.collection('user_data').countDocuments(query);

    res.json({
      success: true,
      data: users,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total,
        pages: Math.ceil(total / limit)
      }
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

// Usage: GET /users?gender=Male&page=1&limit=20
```

## Method 6: Using Aggregation Pipeline (for complex queries)

```javascript
async function filterWithAggregation(filterCriteria) {
  const pipeline = [
    {
      $match: filterCriteria // { gender: 'Male' }
    },
    {
      $group: {
        _id: '$gender',
        count: { $sum: 1 },
        users: { $push: '$$ROOT' }
      }
    }
  ];

  const results = await db.collection('user_data').aggregate(pipeline).toArray();
  return results;
}

// Usage
const results = await filterWithAggregation({ gender: 'Male' });
```

## Performance Tips

```javascript
// 1. Create index on frequently filtered columns
db.collection('user_data').createIndex({ gender: 1 });
db.collection('user_data').createIndex({ username: 1 });

// 2. Use projection to limit fields
const maleUsers = await User.find({ gender: 'Male' })
  .select('username gender')
  .lean(); // For faster performance

// 3. Batch processing for large datasets
const batch = await User.find({ gender: 'Male' })
  .batchSize(1000)
  .cursor();
```

Choose the method based on your needs:
- **Method 1**: Simple, quick filtering
- **Method 2**: Reusable, flexible filtering
- **Method 3**: When using Mongoose ODM
- **Method 4**: With pagination & sorting
- **Method 5**: REST API integration
- **Method 6**: Complex analytics queries
